patch:
--- a/comparator.v
+++ b/comparator.v
@@ -1,9 +1,9 @@
 module magnitude_comparator(
   input [63:0] val_x, val_y,
   input enable,
   output reg equal, greater, less
 );
-  always @(val_x) begin
+  always @(val_x or val_y or enable) begin
     if (!enable) begin
       equal <= 1'b0;
       greater <= 1'b0;

before_code:
module magnitude_comparator(
  input [63:0] val_x, val_y,
  input enable,
  output reg equal, greater, less
);
  always @(val_x) begin
    if (!enable) begin
      equal <= 1'b0;
      greater <= 1'b0;
      less <= 1'b0;
    end else begin
      if (val_x == val_y)
        equal <= 1'b1;
      else if (val_x > val_y)
        greater <= 1'b1;
      else
        less <= 1'b1;
    end
  end
endmodule

after_code:
module magnitude_comparator(
  input [63:0] val_x, val_y,
  input enable,
  output reg equal, greater, less
);
  always @(val_x or val_y or enable) begin
    if (!enable) begin
      equal <= 1'b0;
      greater <= 1'b0;
      less <= 1'b0;
    end else begin
      if (val_x == val_y)
        equal <= 1'b1;
      else if (val_x > val_y)
        greater <= 1'b1;
      else
        less <= 1'b1;
    end
  end
endmodule
